import React, { useState } from 'react';
import { Link } from 'react-router-dom';

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);

  // Updated links array with the "Blog" link
  const links = [
    { name: "Home", href: "/" },
    { name: "Projects", href: "/projects" },
    { name: "Services", href: "/services" },
    { name: "About", href: "/about" },
    { name: "Contact", href: "/contact" },
    { name: "Blog", href: "/blog" },  // Blog link added
  ];

  return (
    <header className="main-header">
      <div className="header-container">
        <h1 className="logo-text">Thynexis</h1>
        <button className="menu-toggle" onClick={() => setMenuOpen(!menuOpen)}>
          <span className="hamburger" />
          <span className="hamburger" />
          <span className="hamburger" />
        </button>
        <nav className={`nav-links ${menuOpen ? 'active' : ''}`}>
          {links.map((link) => (
            <Link key={link.name} to={link.href} className="nav-item" onClick={() => setMenuOpen(false)}>
              {link.name}
            </Link>
          ))}
        </nav>

        {/* Contact Info inside Hamburger Menu */}
        <div className={`contact-info ${menuOpen ? 'active' : ''}`}>
          <a href="tel:+918700969107" className="contact-item" onClick={() => setMenuOpen(false)}>
            <i className="fas fa-phone-alt"></i> (+91) 8700969107
          </a>
          <a href="mailto:contact@projectbanao.in" className="contact-item" onClick={() => setMenuOpen(false)}>
            <i className="fas fa-envelope"></i> contact@projectbanao.in
          </a>
        </div>
      </div>
    </header>
  );
}
